#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

long long calculateMaxProfit(int n, int *prices) {
    long long buy1 = LLONG_MIN;
    long long sell1 = 0;
    long long buy2 = LLONG_MIN;
    long long sell2 = 0;
    for (int i = 0; i < n; ++i) {
        int p = prices[i];
        if (-p > buy1) buy1 = -p;
        if (buy1 + p > sell1) sell1 = buy1 + p;
        if (sell1 - p > buy2) buy2 = sell1 - p;
        if (buy2 + p > sell2) sell2 = buy2 + p;
    }
    return sell2;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        printf("%lld\n", calculateMaxProfit(N, arr));
        free(arr);
    }
    return 0;
}

