using namespace std;

long long calculateMaxProfit(int n, const vector<int>& prices) {
    long long buy1 = LLONG_MIN, sell1 = 0, buy2 = LLONG_MIN, sell2 = 0;
    for (int price : prices) {
        buy1 = max(buy1, -(long long)price);
        sell1 = max(sell1, buy1 + price);
        buy2 = max(buy2, sell1 - price);
        sell2 = max(sell2, buy2 + price);
    }
    return sell2;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
